SELECT EXISTS (
    SELECT 1
    FROM TRIP t
    LEFT JOIN TRIP_MEMBER tm
      ON tm.trip_id = t.trip_id
     AND tm.user_id = #{userId}
     AND tm.invite_status = 'ACCEPTED'
    WHERE t.trip_id = #{tripId}
      AND (t.owner_user_id = #{userId} OR tm.trip_member_id IS NOT NULL)
)

SELECT 
FROM VOTE
WHERE trip_id = #{tripId}
  AND vote_id = #{voteId}

SELECT vote_option_id
FROM VOTE_BALLOT
WHERE vote_id = #{voteId}
  AND user_id = #{userId}

SELECT EXISTS (
    SELECT 1 FROM VOTE_OPTION
    WHERE vote_id = #{voteId}
      AND vote_option_id = #{voteOptionId}
)

